20	async function apiFetch<T>(
21	  path: string,
22	  options: RequestInit = {}
23	): Promise<T> {
24	  const token = getToken();
25	  const headers: Record<string, string> = {
26	    "Content-Type": "application/json",
27	    ...(options.headers as Record<string, string>),
28	  };
29	  if (token) headers["Authorization"] = `Bearer ${token}`;
30	
31	  const res = await fetch(`${BASE_URL}${path}`, { ...options, headers });
32	  if (!res.ok) {
33	    const err = await res.json().catch(() => ({}));
34	    throw new Error(err?.detail?.error?.message || err?.detail || res.statusText);
35	  }
36	  return res.json() as Promise<T>;
37	}
