66	export async function* sendChatMessage(
67	  campaignId: string,
68	  message: string
69	): AsyncGenerator<{ type: "token" | "done"; content?: string; extracted_params?: Record<string, unknown> }> {
70	  const token = getToken();
71	  const headers: Record<string, string> = { "Content-Type": "application/json" };
72	  if (token) headers["Authorization"] = `Bearer ${token}`;
73	
74	  const res = await fetch(`${BASE_URL}/api/v1/campaigns/${campaignId}/chat`, {
75	    method: "POST",
76	    headers,
77	    body: JSON.stringify({ message }),
78	  });
79	
80	  if (!res.ok || !res.body) throw new Error("Chat stream failed");
81	
82	  const reader = res.body.getReader();
83	  const decoder = new TextDecoder();
84	  let buffer = "";
85	
86	  while (true) {
87	    const { done, value } = await reader.read();
88	    if (done) break;
89	    buffer += decoder.decode(value, { stream: true });
90	    const lines = buffer.split("\n");
91	    buffer = lines.pop() ?? "";
92	    for (const line of lines) {
93	      if (line.startsWith("data: ")) {
94	        try {
95	          yield JSON.parse(line.slice(6));
96	        } catch {
97	          // skip malformed
98	        }
99	      }
100	    }
101	  }
102	}
