147	export function openCampaignStream(
148	  campaignId: string,
149	  onEvent: (event: Record<string, unknown>) => void,
150	  onClose: () => void
151	): () => void {
152	  const token = getToken();
153	  const url = `${BASE_URL}/api/v1/campaigns/${campaignId}/stream${token ? `?token=${token}` : ""}`;
154	  const es = new EventSource(url);
155	  es.onmessage = (e) => {
156	    try {
157	      const data = JSON.parse(e.data);
158	      onEvent(data);
159	      if (data.type === "complete") {
160	        es.close();
161	        onClose();
162	      }
163	    } catch {
164	      // skip
165	    }
166	  };
167	  es.onerror = () => { es.close(); onClose(); };
168	  return () => es.close();
169	}
